package value

import (
	"bytes"
	"context"
	"fmt"
	"testing"

	genericapirequest "k8s.io/apiserver/pkg/endpoints/request"
)

// mockTransformer provides a simple test implementation of the Transformer interface
type mockTransformer struct {
	encryptedData []byte
	decryptedData []byte
	encryptErr    error
	decryptErr    error
	decryptStale  bool
	// track what was received for assertion
	receivedToStorage   []byte
	receivedFromStorage []byte
}

func (m *mockTransformer) TransformToStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
	m.receivedToStorage = data
	if m.encryptErr != nil {
		return nil, m.encryptErr
	}
	return m.encryptedData, nil
}

func (m *mockTransformer) TransformFromStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
	m.receivedFromStorage = data
	if m.decryptErr != nil {
		return nil, false, m.decryptErr
	}
	return m.decryptedData, m.decryptStale, nil
}

// TestDefaultContext verifies that DefaultContext correctly implements the Context interface
func TestDefaultContext(t *testing.T) {
	testData := []byte("test-authenticated-data")
	ctx := DefaultContext(testData)

	result := ctx.AuthenticatedData()
	if !bytes.Equal(result, testData) {
		t.Errorf("DefaultContext.AuthenticatedData() = %q, want %q", result, testData)
	}
}

// TestDefaultContextEmpty verifies that DefaultContext works with empty data
func TestDefaultContextEmpty(t *testing.T) {
	ctx := DefaultContext([]byte{})
	result := ctx.AuthenticatedData()
	if len(result) != 0 {
		t.Errorf("DefaultContext.AuthenticatedData() should return empty slice, got %q", result)
	}
}

// TestTransformerRoundTrip tests the basic encrypt/decrypt contract of the Transformer interface
func TestTransformerRoundTrip(t *testing.T) {
	tests := []struct {
		name          string
		originalData  []byte
		encryptedData []byte
		authenticData []byte
		expectError   bool
	}{
		{
			name:          "simple round trip",
			originalData:  []byte("secret-data"),
			encryptedData: []byte("encrypted-secret-data"),
			authenticData: []byte("auth-data"),
			expectError:   false,
		},
		{
			name:          "empty original data",
			originalData:  []byte{},
			encryptedData: []byte("encrypted-empty"),
			authenticData: []byte("auth"),
			expectError:   false,
		},
		{
			name:          "large data",
			originalData:  bytes.Repeat([]byte("x"), 10000),
			encryptedData: bytes.Repeat([]byte("y"), 10000),
			authenticData: []byte("large"),
			expectError:   false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			transformer := &mockTransformer{
				encryptedData: tt.encryptedData,
				decryptedData: tt.originalData,
			}

			ctx := context.Background()
			authCtx := DefaultContext(tt.authenticData)

			// Test encryption
			encrypted, err := transformer.TransformToStorage(ctx, tt.originalData, authCtx)
			if err != nil && !tt.expectError {
				t.Fatalf("TransformToStorage failed: %v", err)
			}
			if !bytes.Equal(encrypted, tt.encryptedData) {
				t.Errorf("TransformToStorage returned %q, want %q", encrypted, tt.encryptedData)
			}

			// Test decryption
			decrypted, stale, err := transformer.TransformFromStorage(ctx, encrypted, authCtx)
			if err != nil && !tt.expectError {
				t.Fatalf("TransformFromStorage failed: %v", err)
			}
			if !bytes.Equal(decrypted, tt.originalData) {
				t.Errorf("TransformFromStorage returned %q, want %q", decrypted, tt.originalData)
			}
		})
	}
}

// TestPrefixTransformerWithoutMatch verifies error when no prefix matches
func TestPrefixTransformerWithoutMatch(t *testing.T) {
	testErr := fmt.Errorf("no matching transformer")
	transformer := &mockTransformer{
		encryptedData: []byte("encrypted"),
		decryptedData: []byte("decrypted"),
	}

	p := NewPrefixTransformers(testErr,
		PrefixTransformer{Prefix: []byte("aes:"), Transformer: transformer},
	)

	ctx := context.Background()

	// Try to decrypt data with a prefix that doesn't match
	result, stale, err := p.TransformFromStorage(ctx, []byte("unknown:data"), nil)

	if err != testErr {
		t.Errorf("TransformFromStorage error = %v, want %v", err, testErr)
	}
	if result != nil {
		t.Errorf("TransformFromStorage result should be nil on error, got %q", result)
	}
	if stale {
		t.Errorf("TransformFromStorage stale should be false when error occurs, got true")
	}
}

// TestPrefixTransformerStaleMarking verifies that non-first transformers mark data as stale
func TestPrefixTransformerStaleMarking(t *testing.T) {
	tests := []struct {
		name             string
		dataPrefix       []byte
		transformerIndex int
		expectStale      bool
	}{
		{
			name:             "first transformer - not stale",
			dataPrefix:       []byte("aes:"),
			transformerIndex: 0,
			expectStale:      false,
		},
		{
			name:             "second transformer - stale",
			dataPrefix:       []byte("kms:"),
			transformerIndex: 1,
			expectStale:      true,
		},
		{
			name:             "third transformer - stale",
			dataPrefix:       []byte("legacy:"),
			transformerIndex: 2,
			expectStale:      true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			transformer1 := &mockTransformer{decryptedData: []byte("data1")}
			transformer2 := &mockTransformer{decryptedData: []byte("data2")}
			transformer3 := &mockTransformer{decryptedData: []byte("data3")}

			p := NewPrefixTransformers(fmt.Errorf("no match"),
				PrefixTransformer{Prefix: []byte("aes:"), Transformer: transformer1},
				PrefixTransformer{Prefix: []byte("kms:"), Transformer: transformer2},
				PrefixTransformer{Prefix: []byte("legacy:"), Transformer: transformer3},
			)

			ctx := context.Background()
			data := append(tt.dataPrefix, []byte("encrypted-data")...)

			_, stale, err := p.TransformFromStorage(ctx, data, nil)
			if err != nil {
				t.Fatalf("TransformFromStorage failed: %v", err)
			}

			if stale != tt.expectStale {
				t.Errorf("stale = %v, want %v", stale, tt.expectStale)
			}
		})
	}
}

// TestPrefixTransformerEmptyPrefix verifies that empty prefix (identity transformer) works
func TestPrefixTransformerEmptyPrefix(t *testing.T) {
	transformer := &mockTransformer{
		decryptedData: []byte("data"),
		encryptedData: []byte("encrypted"),
	}

	p := NewPrefixTransformers(fmt.Errorf("no match"),
		PrefixTransformer{Prefix: []byte{}, Transformer: transformer},
	)

	ctx := context.Background()
	data := []byte("test-data")

	// Test decryption with empty prefix - should match any data
	result, _, err := p.TransformFromStorage(ctx, data, nil)
	if err != nil {
		t.Fatalf("TransformFromStorage failed: %v", err)
	}
	if !bytes.Equal(result, []byte("data")) {
		t.Errorf("TransformFromStorage returned %q, want %q", result, []byte("data"))
	}

	// Test encryption - should add empty prefix (no-op)
	encrypted, err := p.TransformToStorage(ctx, data, nil)
	if err != nil {
		t.Fatalf("TransformToStorage failed: %v", err)
	}
	if !bytes.Equal(encrypted, []byte("encrypted")) {
		t.Errorf("TransformToStorage returned %q, want %q", encrypted, []byte("encrypted"))
	}
}

// TestPrefixTransformerEmptyData verifies correct handling of empty data
func TestPrefixTransformerEmptyData(t *testing.T) {
	transformer := &mockTransformer{
		decryptedData: []byte("decrypted"),
		encryptedData: []byte("encrypted"),
	}

	p := NewPrefixTransformers(fmt.Errorf("no match"),
		PrefixTransformer{Prefix: []byte("aes:"), Transformer: transformer},
	)

	ctx := context.Background()

	// Empty data cannot match any prefix that has length
	_, _, err := p.TransformFromStorage(ctx, []byte{}, nil)
	if err == nil {
		t.Errorf("TransformFromStorage with empty data should return error")
	}

	// Encryption should work with empty data
	result, err := p.TransformToStorage(ctx, []byte{}, nil)
	if err != nil {
		t.Fatalf("TransformToStorage with empty data failed: %v", err)
	}
	// Result should be prefix + encrypted data
	expected := append([]byte("aes:"), []byte("encrypted")...)
	if !bytes.Equal(result, expected) {
		t.Errorf("TransformToStorage returned %q, want %q", result, expected)
	}
}

// TestTransformerErrorHandling verifies error propagation from underlying transformers
func TestTransformerErrorHandling(t *testing.T) {
	tests := []struct {
		name        string
		transformers []PrefixTransformer
		data        []byte
		operation   string
		expectErr   bool
	}{
		{
			name: "encryption error",
			transformers: []PrefixTransformer{
				{
					Prefix: []byte("aes:"),
					Transformer: &mockTransformer{
						encryptErr: fmt.Errorf("encryption failed"),
					},
				},
			},
			data:      []byte("data"),
			operation: "encrypt",
			expectErr: true,
		},
		{
			name: "decryption error with matching prefix",
			transformers: []PrefixTransformer{
				{
					Prefix: []byte("aes:"),
					Transformer: &mockTransformer{
						decryptErr: fmt.Errorf("decryption failed"),
					},
				},
			},
			data:      []byte("aes:encrypted"),
			operation: "decrypt",
			expectErr: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			p := NewPrefixTransformers(fmt.Errorf("no match"), tt.transformers...)
			ctx := context.Background()

			if tt.operation == "encrypt" {
				_, err := p.TransformToStorage(ctx, tt.data, nil)
				if !tt.expectErr && err != nil {
					t.Fatalf("TransformToStorage unexpected error: %v", err)
				}
				if tt.expectErr && err == nil {
					t.Fatalf("TransformToStorage should have errored")
				}
			} else if tt.operation == "decrypt" {
				_, _, err := p.TransformFromStorage(ctx, tt.data, nil)
				if !tt.expectErr && err != nil {
					t.Fatalf("TransformFromStorage unexpected error: %v", err)
				}
				if tt.expectErr && err == nil {
					t.Fatalf("TransformFromStorage should have errored")
				}
			}
		})
	}
}

// TestMultiplePrefixTransformers verifies correct transformer selection and write behavior
func TestMultiplePrefixTransformers(t *testing.T) {
	transformer1 := &mockTransformer{
		decryptedData: []byte("result1"),
		encryptedData: []byte("encrypted1"),
	}
	transformer2 := &mockTransformer{
		decryptedData: []byte("result2"),
		encryptedData: []byte("encrypted2"),
	}
	transformer3 := &mockTransformer{
		decryptedData: []byte("result3"),
		encryptedData: []byte("encrypted3"),
	}

	p := NewPrefixTransformers(fmt.Errorf("no match"),
		PrefixTransformer{Prefix: []byte("aes:"), Transformer: transformer1},
		PrefixTransformer{Prefix: []byte("kms:"), Transformer: transformer2},
		PrefixTransformer{Prefix: []byte("legacy:"), Transformer: transformer3},
	)

	ctx := context.Background()

	tests := []struct {
		name                 string
		data                 []byte
		expectTransformer    *mockTransformer
		expectResult         []byte
		expectReceivedData   []byte
	}{
		{
			name:                 "first prefix matches",
			data:                 []byte("aes:encrypted1"),
			expectTransformer:    transformer1,
			expectResult:         []byte("result1"),
			expectReceivedData:   []byte("encrypted1"),
		},
		{
			name:                 "second prefix matches",
			data:                 []byte("kms:encrypted2"),
			expectTransformer:    transformer2,
			expectResult:         []byte("result2"),
			expectReceivedData:   []byte("encrypted2"),
		},
		{
			name:                 "third prefix matches",
			data:                 []byte("legacy:encrypted3"),
			expectTransformer:    transformer3,
			expectResult:         []byte("result3"),
			expectReceivedData:   []byte("encrypted3"),
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			result, _, err := p.TransformFromStorage(ctx, tt.data, nil)
			if err != nil {
				t.Fatalf("TransformFromStorage failed: %v", err)
			}

			if !bytes.Equal(result, tt.expectResult) {
				t.Errorf("TransformFromStorage returned %q, want %q", result, tt.expectResult)
			}

			if !bytes.Equal(tt.expectTransformer.receivedFromStorage, tt.expectReceivedData) {
				t.Errorf("transformer received %q, want %q", tt.expectTransformer.receivedFromStorage, tt.expectReceivedData)
			}
		})
	}

	// Test that write always uses the first transformer
	result, err := p.TransformToStorage(ctx, []byte("data"), nil)
	if err != nil {
		t.Fatalf("TransformToStorage failed: %v", err)
	}

	expected := append([]byte("aes:"), []byte("encrypted1")...)
	if !bytes.Equal(result, expected) {
		t.Errorf("TransformToStorage returned %q, want %q", result, expected)
	}

	// Verify that only the first transformer was used
	if !bytes.Equal(transformer1.receivedToStorage, []byte("data")) {
		t.Errorf("first transformer received %q, want %q", transformer1.receivedToStorage, []byte("data"))
	}
	if len(transformer2.receivedToStorage) > 0 {
		t.Errorf("second transformer should not be called for write, but received %q", transformer2.receivedToStorage)
	}
	if len(transformer3.receivedToStorage) > 0 {
		t.Errorf("third transformer should not be called for write, but received %q", transformer3.receivedToStorage)
	}
}

// TestContextPropagation verifies that the context parameter is properly handled
func TestContextPropagation(t *testing.T) {
	transformer := &mockTransformer{
		decryptedData: []byte("result"),
		encryptedData: []byte("encrypted"),
	}

	p := NewPrefixTransformers(fmt.Errorf("no match"),
		PrefixTransformer{Prefix: []byte("aes:"), Transformer: transformer},
	)

	authData := []byte("authenticated-data")
	authCtx := DefaultContext(authData)

	ctx := context.Background()

	// Decrypt
	_, _, err := p.TransformFromStorage(ctx, []byte("aes:data"), authCtx)
	if err != nil {
