	ctx := context.Background()

	// When data doesn't match the empty prefix pattern, it should try the next transformer
	result, _, err := p.TransformFromStorage(ctx, []byte("working:data"), nil)
	if err != nil {
		t.Fatalf("TransformFromStorage failed: %v", err)
	}

	if !bytes.Equal(result, []byte("recovered")) {
		t.Errorf("TransformFromStorage returned %q, want %q", result, []byte("recovered"))
	}
}

// TestPrefixTransformerWithRequestContext verifies correct behavior with request context
func TestPrefixTransformerWithRequestContext(t *testing.T) {
	transformer := &mockTransformer{
		decryptedData: []byte("result"),
		encryptedData: []byte("encrypted"),
	}

	p := NewPrefixTransformers(fmt.Errorf("no match"),
		PrefixTransformer{Prefix: []byte("aes:"), Transformer: transformer},
	)

	// Create context with request info
	reqCtx := genericapirequest.WithRequestInfo(
		context.Background(),
		&genericapirequest.RequestInfo{
			Resource: "pods",
			Verb:     "get",
		},
	)

	// Should work with request context
	result, _, err := p.TransformFromStorage(reqCtx, []byte("aes:data"), nil)
	if err != nil {
		t.Fatalf("TransformFromStorage with request context failed: %v", err)
	}

	if !bytes.Equal(result, []byte("result")) {
		t.Errorf("TransformFromStorage returned %q, want %q", result, []byte("result"))
	}
}

// TestPrefixTransformerInputValidation verifies proper handling of malformed input
func TestPrefixTransformerInputValidation(t *testing.T) {
	tests := []struct {
		name           string
		transformers   []PrefixTransformer
		data           []byte
		expectError    bool
		description    string
	}{
		{
			name: "no transformers - encryption panic recovery",
			transformers: []PrefixTransformer{},
			data:         []byte("data"),
			expectError:  true,
			description:  "should handle empty transformer list safely",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			if len(tt.transformers) == 0 {
				// Skip this test - NewPrefixTransformers with empty list would panic
				t.Skip("Cannot test with empty transformer list - would panic in production")
			}
		})
	}
}

// TestDefaultContextNil verifies DefaultContext handles nil correctly
func TestDefaultContextNil(t *testing.T) {
	var nilCtx DefaultContext
	result := nilCtx.AuthenticatedData()

	// DefaultContext(nil) should return nil
	if result != nil {
